class Solution {
public:
    int longestSubsequence(string s, int k) {
        int longest = 0;
        for (int i = 0; i < s.length(); i++) {
            long current = 0;
            for (int j = i; j < s.length(); j++) {
                current = (current << 1) | (s[j] - '0');
                if (current > k) {
                    break;
                }
                longest = max(longest, j - i + 1);
            }
        }
        return longest;
    }
};
